const input = $('Workflow Input Trigger').first().json;
const dmChannel = $('Open Bot DM').first().json.channel?.id || '';
return [{ json: { ...input, channelId: dmChannel } }];

const input = $('Set Channel ID').first().json;

const assistantName = input.assistant_name || 'Aria';
const assistantEmoji = input.assistant_emoji || ':robot_face:';
const assistantPersona = input.assistant_persona || 'direct, action-oriented, and conversational';
const repName = input.repName || (input.email || '').split('@')[0].replace(/\./g, ' ').replace(/\b\w/g, c => c.toUpperCase()) || 'Rep';
const timezone = input.timezone || 'America/Los_Angeles';

const accountName = input.accountName || 'Unknown Account';
const meetingSubject = input.meetingSubject || 'Customer Meeting';
const meetingTime = input.meetingTime || '';
const participants = input.participants || '';
const opportunityName = input.opportunityName || '';
const opportunityStage = input.opportunityStage || '';
const opportunityAmount = input.opportunityAmount || '';
const opportunityCloseDate = input.opportunityCloseDate || '';
const opportunityEngagement = input.opportunityEngagement || '';
const opportunityCrmId = input.opportunityCrmId || '';
const hasOpportunity = !!(opportunityName && opportunityName !== 'N/A' && opportunityName.trim());

const currentDate = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const timeStr = new Date().toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: timezone });
const emojiClean = assistantEmoji.replace(/:/g, '');

// Calculate minutes until meeting
let minutesUntil = '';
if (meetingTime) {
  const meetingMs = parseInt(meetingTime);
  if (!isNaN(meetingMs)) {
    const diffMin = Math.round((meetingMs - Date.now()) / 60000);
    if (diffMin > 0) minutesUntil = diffMin + ' minutes';
    else minutesUntil = 'starting now';
  }
}

// Format actual meeting date/time
let meetingDateStr = '';
if (meetingTime) {
  const meetingMs = parseInt(meetingTime);
  if (!isNaN(meetingMs)) {
    const meetingDate = new Date(meetingMs);
    meetingDateStr = meetingDate.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: timezone }) + ' at ' + meetingDate.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: timezone });
  }
}

// Build context about the opportunity if available
let dealContext = '';
if (hasOpportunity) {
  dealContext = `\n━━━ DEAL CONTEXT ━━━
Opportunity: ${opportunityName}
Stage: ${opportunityStage}
Amount: ${opportunityAmount}
Close Date: ${opportunityCloseDate}
Engagement: ${opportunityEngagement}
${opportunityCrmId ? 'People.ai: https://app.people.ai/opportunities/' + opportunityCrmId : ''}
`;
}

const blockKitRules = `OUTPUT FORMAT — CRITICAL:
Respond with ONLY a valid JSON object. No prose. No explanation. No markdown code fences (no backticks).

Your response must have exactly this shape:
{
  "notification_text": "string — one sentence, shown in push notifications",
  "blocks": [ array of valid Slack Block Kit blocks ]
}

BLOCK KIT STRUCTURE RULES:
- Use a "header" block for the message title (plain_text only, emoji: true)
- Use "section" blocks with "mrkdwn" text for all body content
- Use "divider" blocks between major sections (maximum 2 per message)
- Use "section" with "fields" for two-column data (engagement scores, metrics)
  - MAXIMUM 10 fields per section block (Slack API hard limit)
- Use "context" block at the bottom for timestamp and data source
- Maximum 50 blocks per message

MRKDWN RULES (inside all text fields):
- Bold: *text* — single asterisks only
- Line break: \\n
- Blank line: \\n\\n
- Bullet points: use the • character on its own line
- NO ## headers — use *bold text* on its own line instead
- NO **double asterisks**
- NO standard markdown links [text](url) — use <https://url|text>
- NO dash bullets (-)

EMOJI STATUS INDICATORS:
🚀 Acceleration / strong momentum
⚠️ Risk pattern detected
💎 Hidden upside opportunity
🔴 Stalled / critical risk
✅ Healthy / on track
📈 Engagement rising
📉 Engagement falling
🤝 Meeting / relationship building`;

const systemPrompt = `You are ${assistantName}, a personal sales assistant for ${repName}. You are preparing them for an upcoming customer meeting.

Your personality: ${assistantPersona}

Today is ${currentDate}. ${repName} is in ${timezone}.

━━━ MEETING DETAILS ━━━
Subject: ${meetingSubject}
Account: ${accountName}
Time: ${meetingDateStr || 'Today'}${minutesUntil ? ' (in ' + minutesUntil + ')' : ''}
Participants: ${participants || 'Not available'}
${dealContext}

You have access to People.ai MCP tools. Use them to research:
- The account's engagement history and recent activity (emails, meetings, calls)
- Meeting participants — look up the specific activity/meeting to find BOTH internal (People.ai users) and external attendees. Include internal team members in People in the Room with the :backstory: emoji tag. CRITICAL: The emoji is exactly :backstory: — NOT :backstage: or any other variation. If Slack @mentions (<@SLACK_ID>) are provided in the participant data, preserve them exactly in your output.
- Each participant's role, title, and recent touchpoints. IMPORTANT: CRITICAL: Titles/roles ARE provided in the Participants field above (after the — dash). You MUST use them EXACTLY as listed. Do NOT replace them with titles from People.ai MCP lookups. The participant data is authoritative — MCP data may have outdated or incorrect roles.
- ${hasOpportunity ? 'Deal progression, engagement trends, and risk signals for this opportunity' : 'Any open opportunities or past deals with this account'}
- Recent account news or changes

Prepare a 60-second meeting prep briefing following this structure:

1. Header block — "${emojiClean} Meeting Prep — ${accountName} — ${meetingSubject}"
2. Show the meeting date and time prominently near the top: ${meetingDateStr || "Today"}${minutesUntil ? " (" + minutesUntil + " from now)" : ""}
2. ONE section block — 2 sentences, no label. Start with a status indicator emoji. Frame the summary around the meeting subject — what is this meeting about, what is the current state of that topic, and what should ${repName} know going in. Weave in deal context (stage, amount) only if directly relevant to the meeting topic. If the subject is generic (e.g. "Sync", "Check-in"), fall back to overall engagement trend and ${hasOpportunity ? 'deal status' : 'relationship status'}.
3. Divider
4. ONE section block combining What to Ask About AND Watch Out For:
   "*What to Ask About*\n• item1\n• item2\n\n*Watch Out For*\n• item1\n• item2"
   2 ask items + 1-2 watch items. One line each.
5. Section block with "fields" array for People in the Room — use TWO-COLUMN fields layout (2 contacts per row). Each field: "*Name* — Role\n<signal>". The signal is a brief qualitative insight about the person — what they care about, what they're working on, or their stance on the deal. Examples: "leading CAB presentation on SalesAI use cases", "concerned about forecasting discrepancies", "coordinating UK expansion timing". NEVER include email counts, meeting counts, or activity volume stats. Only show "Last: <date>" prefix if last contact was 30+ days ago. Show up to 10 participants (Slack fields limit). If there are more than 10, show the 10 most relevant and add a context line below the fields: "_and X others_". Include both internal and external attendees. Layout: fields array must alternate left/right columns — internal on the LEFT, external on the RIGHT. Pair them row by row. Internal participants may already include Slack @mentions like \`<@U061WJ6RMJS>\` in the participant data. If present, use ONLY the @mention (Slack will render the display name automatically): "*<@U061WJ6RMJS>*:backstory: — Lead CSM". Do NOT repeat the name after the @mention. If no @mention is provided, use the name: "*Kole Franklin*:backstory: — Lead CSM". CRITICAL: preserve \`<@...>\` mentions exactly as-is in the output — do NOT escape, modify, or remove them.
6. Context block — "People.ai • Type \`stop briefs\` to pause meeting briefs · \`start briefs\` to resume"

CRITICAL LAYOUT RULES:
- DO NOT use a label like "Account Snapshot" — just write the text directly.
- People in the Room MUST use "fields" (two-column), NOT separate section blocks per person.
- What to Ask + Watch Out MUST be in ONE section block, not separate blocks.
- DO NOT include a deal status table or open opportunities table.
- Target: 6-7 blocks total. Fewer blocks = more compact in Slack.
Keep the entire message under 1500 characters of visible text. Brevity is more important than completeness.

${blockKitRules}`;

const agentPrompt = `Prepare a meeting brief for ${repName} who has a meeting with ${accountName}${minutesUntil ? ' in ' + minutesUntil : ' today'}.

Meeting subject: ${meetingSubject}
Participants: ${participants || 'Unknown — research the account contacts'}

Use the People.ai MCP tools to research:
1. The account "${accountName}" — engagement history, recent activity
2. Each participant listed — role, title, recent touchpoints, engagement
3. ${hasOpportunity ? 'The opportunity "' + opportunityName + '" — deal health, progression, risks' : 'Any open opportunities or past deals with "' + accountName + '"'}
4. Recent emails, meetings, and calls with this account

Then generate the meeting prep briefing as a Block Kit JSON object following the format in your system instructions. Output ONLY the JSON object, nothing else.`;

return [{
  json: {
    userId: input.userId,
    slackUserId: input.slackUserId,
    channelId: input.channelId,
    assistantName,
    assistantEmoji,
    repName,
    accountName,
    systemPrompt,
    agentPrompt
  }
}];

// Parse the agent's Block Kit JSON output
const agentOutput = $('Meeting Brief Agent').first().json.output;

let parsed;
try {
  // Try to extract JSON from the output — Claude sometimes wraps it in prose or code fences
  let cleaned = agentOutput;

  // Remove code fences
  cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

  // If it doesn't start with {, try to find JSON object in the text
  if (!cleaned.startsWith('{')) {
    const jsonMatch = cleaned.match(/\{[\s\S]*"blocks"[\s\S]*\}/);
    if (jsonMatch) {
      cleaned = jsonMatch[0];
    }
  }

  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback: split raw output into chunks that fit Slack's 3000 char limit per block
  const maxLen = 2900;
  const text = agentOutput || 'Briefing generation failed.';
  const chunks = [];
  for (let i = 0; i < text.length; i += maxLen) {
    chunks.push(text.slice(i, i + maxLen));
  }

  const blocks = chunks.map((chunk, idx) => ({
    type: "section",
    text: { type: "mrkdwn", text: idx === 0 ? chunk : '...' + chunk }
  }));

  parsed = {
    notification_text: "Your briefing is ready",
    blocks
  };
}



  // Enforce Slack limits
if (parsed.blocks) {
  parsed.blocks = parsed.blocks.map(block => {
    // Max 10 fields per section
    if (block.fields && block.fields.length > 10) {
      block.fields = block.fields.slice(0, 10);
    }
    // Max 3000 chars per text field in section blocks
    if (block.text && block.text.text && block.text.text.length > 3000) {
      block.text.text = block.text.text.slice(0, 2997) + '...';
    }
    // Max 3000 chars per field text
    if (block.fields) {
      block.fields = block.fields.map(f => {
        if (f.text && f.text.length > 2000) {
          f.text = f.text.slice(0, 1997) + '...';
        }
        return f;
      });
    }
    return block;
  });
  // Max 50 blocks
  if (parsed.blocks.length > 50) {
    parsed.blocks = parsed.blocks.slice(0, 50);
  }
}

return [{
  json: {
    notificationText: parsed.notification_text || "Your briefing",
    blocks: JSON.stringify(parsed.blocks),
    rawContent: agentOutput
  }
}];

// Gather data for conversation bookend (Meeting Brief).

const identity = $('Resolve Meeting Identity').first().json;
const sendResult = $('Send Meeting Brief').first().json;
const agentOutput = $('Meeting Brief Agent').first().json.output || '';
const inputData = $('Workflow Input Trigger').first().json;

// userId and organizationId from input and Resolve Meeting Identity
const userId = identity.userId || inputData.userId || null;
const organizationId = inputData.organization_id || null;

// Channel and thread_ts from the Slack response
const channelId = sendResult.channel || identity.channelId || '';
const threadTs = sendResult.ts || '';

const agentConfig = {
  model: 'claude-sonnet-4-5-20250929',
  mcpEndpoint: 'https://mcp.people.ai/mcp',
  assistantName: identity.assistantName || 'Aria',
  assistantEmoji: identity.assistantEmoji || ':robot_face:',
  accountName: identity.accountName || ''
};

// Meeting brief conversations expire after 4 hours
const expiresAt = new Date(Date.now() + 4 * 60 * 60 * 1000).toISOString();

// User message = meeting context (what triggered the brief)
const meetingSubject = inputData.meetingSubject || 'Customer Meeting';
const accountName = inputData.accountName || identity.accountName || 'Unknown';
const participants = inputData.participants || '';
const userMessage = 'Meeting prep: ' + meetingSubject + ' with ' + accountName
  + (participants ? ' (' + participants + ')' : '');

return [{
  json: {
    organizationId: organizationId,
    userId: userId,
    channelId: channelId,
    threadTs: threadTs,
    workflowType: 'meeting_prep',
    agentConfig: agentConfig,
    expiresAt: expiresAt,
    userMessage: userMessage,
    assistantMessage: agentOutput
  }
}];

